mapper.select:
select * from sub_orders

     and `id` = #{id}
     and `order_id` = #{orderId}
     and `customer_id` = #{customerId}
     and `user_id` = #{userId}
     and `iam_id` = #{iamId}
     and `repair_time` = #{repairTime}
     and `iam_content` like concat('%', #{iamContent}, '%')
     and `state` = #{state}

order by id desc
